import React from "react"
import { IoCloseCircleSharp, IoHammerSharp} from "react-icons/io5";


class User extends React.Component {
    constructor(props) {

    }
    user = this.props.user
    render() {
        return (
            <div className="user">
                <div className="change-icons">
                    <IoHammerSharp className="edit-icon" />
                    <IoCloseCircleSharp className="delete-icon" onClick={() => this.props.onDelete(this.props.user.id)} />
                </div>
                <h3 style={{fontWeight: "bold"}}>{this.user.firstname}</h3>
                <h4 style={{color: "white", fontWeight: "100", textIndent: "5px"}}>{this.user.info}</h4>
                <b>{"- " + this.user.job}</b>
            </div>
        )
    }
}



export default User
